def format_activity(activity):
    if activity['type'] == 'type1':
        return {
            'id': activity['id'],
            'name': activity['name'],
            'details': activity['details']
        }
    elif activity['type'] == 'type2':
        return {
            'id': activity['id'],
            'title': activity['title'],
            'description': activity['description']
        }
    elif activity['type'] == 'type3':
        return {
            'id': activity['id'],
            'event': activity['event'],
            'location': activity['location']
        }
    else:
        return None

def get_activities():
    raw_data = fetch_elastic_search_data()  # Assuming this function fetches the raw data
    formatted_activities = [format_activity(activity) for activity in raw_data]
    return formatted_activities

def solve(*args):
